one = &pgdat->node_zones[zoneid];\n\t\t\tif (!populated_zone(zone))\n\t\t\t\tcontinue;\n\n\t\t\t/* Print information about the zonelist */\n\t\t\tprintk(KERN_DEBUG \"mminit::zonelist %s %d:%s = \",\n\t\t\t\tlistid > 0 ? \"thisnode\" : \"general\", nid,\n\t\t\t\tzone->name);\n\n\t\t\t/* Iterate the zonelist */\n\t\t\tfor_each_zone_zonelist(zone, z, zonelist, zoneid)\n\t\t\t\tpr_cont(\"%d:%s \", zone_to_nid(zone), zone->name);\n\t\t\tpr_cont(\"\\n\");\n\t\t}\n\t}\n}\n\nvoid __init mminit_verify_pageflags_layout(void)\n{\n\tint shift, width;\n\tunsigned long or_mask, add_mask;\n\n\tshift = BITS_PER_LONG;\n\twidth = shift - NR_NON_PAGEFLAG_BITS;\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_widths\",\n\t\t\"Section %d Node %d Zone %d Lastcpupid %d Kasantag %d Gen %d Tier %d Flags %d\\n\",\n\t\tSECTIONS_WIDTH,\n\t\tNODES_WIDTH,\n\t\tZONES_WIDTH,\n\t\tLAST_CPUPID_WIDTH,\n\t\tKASAN_TAG_WIDTH,\n\t\tLRU_GEN_WIDTH,\n\t\tLRU_REFS_WIDTH,\n\t\tNR_PAGEFLAGS);\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_shifts\",\n\t\t\"Section %d Node %d Zone %d Lastcpupid %d Kasantag %d\\n\",\n\t\tSECTIONS_SHIFT,\n\t\tNODES_SHIFT,\n\t\tZONES_SHIFT,\n\t\tLAST_CPUPID_SHIFT,\n\t\tKASAN_TAG_WIDTH);\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_pgshifts\",\n\t\t\"Section %lu Node %lu Zone %lu Lastcpupid %lu Kasantag %lu\\n\",\n\t\t(unsigned long)SECTIONS_PGSHIFT,\n\t\t(unsigned long)NODES_PGSHIFT,\n\t\t(unsigned long)ZONES_PGSHIFT,\n\t\t(unsigned long)LAST_CPUPID_PGSHIFT,\n\t\t(unsigned long)KASAN_TAG_PGSHIFT);\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_nodezoneid\",\n\t\t\"Node/Zone ID: %lu -> %lu\\n\",\n\t\t(unsigned long)(ZONEID_PGOFF + ZONEID_SHIFT),\n\t\t(unsigned long)ZONEID_PGOFF);\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_usage\",\n\t\t\"location: %d -> %d layout %d -> %d unused %d -> %d page-flags\\n\",\n\t\tshift, width, width, NR_PAGEFLAGS, NR_PAGEFLAGS, 0);\n#ifdef NODE_NOT_IN_PAGE_FLAGS\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_nodeflags\",\n\t\t\"Node not in page flags\");\n#endif\n#ifdef LAST_CPUPID_NOT_IN_PAGE_FLAGS\n\tmminit_dprintk(MMINIT_TRACE, \"pageflags_layout_nodeflags\",\n\t\t\"Last cpupid not in page flags\");\n#endif\n\n\tif (SECTIONS_WIDTH) {\n\t\tshift -= SECTIONS_WIDTH;\n\t\tBUG_ON(shift != SECTIONS_PGSHIFT);\n\t}\n\tif (NODES_WIDTH) {\n\t\tshift -= NODES_WIDTH;\n\t\tBUG_ON(shift != NODES_PGSHIFT);\n\t}\n\tif (ZONES_WIDTH) {\n\t\tshift -= ZONES_WIDTH;\n\t\tBUG_ON(shift != ZONES_PGSHIFT);\n\t}\n\n\t/* Check for bitmask overlaps */\n\tor_mask = (ZONES_MASK << ZONES_PGSHIFT) |\n\t\t\t(NODES_MASK << NODES_PGSHIFT) |\n\t\t\t(SECTIONS_MASK << SECTIONS_PGSHIFT);\n\tadd_mask = (ZONES_MASK << ZONES_PGSHIFT) +\n\t\t\t(NODES_MASK << NODES_PGSHIFT) +\n\t\t\t(SECTIONS_MASK << SECTIONS_PGSHIFT);\n\tBUG_ON(or_mask != add_mask);\n}\n\nstatic __init int set_mminit_loglevel(char *str)\n{\n\tget_option(&str, &mminit_loglevel);\n\treturn 0;\n}\nearly_param(\"mminit_loglevel\", set_mminit_loglevel);\n#endif /* CONFIG_DEBUG_MEMORY_INIT */\n\nstruct kobject *mm_kobj;\n\n#ifdef CONFIG_SMP\ns32 vm_committed_as_batch = 32;\n\nvoid mm_compute_batch(int overcommit_policy)\n{\n\tu64 memsized_batch;\n\ts32 nr = num_present_cpus();\n\ts32 batch = max_t(s32, nr*2, 32);\n\tunsigned long ram_pages = totalram_pages();\n\n\t/*\n\t * For policy OVERCOMMIT_NEVER, set batch size to 0.4% of\n\t * (total memory/#cpus), and lift it to 25% for other policies\n\t * to easy the possible lock contention for percpu_counter\n\t * vm_committed_as, while the max limit is INT_MAX\n\t */\n\tif (overcommit_policy == OVERCOMMIT_NEVER)\n\t\tmemsized_batch = min_t(u64, ram_pages/nr/256, INT_MAX);\n\telse\n\t\tmemsized_batch = min_t(u64, ram_pages/nr/4, INT_MAX);\n\n\tvm_committed_as_batch = max_t(s32, memsized_batch, batch);\n}\n\nstatic int __meminit mm_compute_batch_notifier(struct notifier_block *self,\n\t\t\t\t\tunsigned long action, void *arg)\n{\n\tswitch (action) {\n\tcase MEM_ONLINE:\n\tcase MEM_OFFLINE:\n\t\tmm_compute_batch(sysctl_overcommit_memory);\n\t\tbreak;\n\tdefault:\n\t\tbreak;\n\t}\n\treturn NOTIFY_OK;\n}\n\nstatic int __init mm_compute_batch_init(void)\n{\n\tmm_compute_batch(sysctl_overcommit_memory);\n\thotplug_memory_notifier(mm_compute_batch_notifier, MM_COMPUTE_BATCH_PRI);\n\treturn 0;\n}\n\n__initcall(mm_compute_batch_init);\n\n#endif\n\nstatic int __init mm_sysfs_init(void)\n{\n\tmm_kobj = kobject_create_and_add(\"mm\", kernel_kobj);\n\tif (!mm_kobj)\n\t\treturn -ENOMEM;\n\n\treturn 0;\n}\npostcore_initcall(mm_sysfs_init);\n\nstatic unsigned long arch_zone_lowest_possible_pfn[MAX_NR_ZONES] __initdata;\nstatic unsigned long arch_zone_highest_possible_pfn[MAX_NR_ZONES] __initdata;\nstatic unsigned long zone_movable_pfn[MAX_NUMNODES] __initdata;\n\nstatic unsigned long required_kernelcore __initdata;\nstatic unsigned long required_kernelcore_percent __initdata;\nstatic unsigned long required_movablecore __initdata;\nstatic unsigned long required_movablecore_percent __initdata;\n\nstatic unsigned long nr_kernel_pages __initdata;\nstatic unsigned long nr_all_pages __initdata;\n\nstatic bool deferred_struct_pages __meminitdata;\n\nstatic DEFINE_PER_CPU(struct per_cpu_nodestat, boot_nodestats);\n\nstatic int __init cmdline_parse_core(char *p, unsigned long *core,\n\t\t\t\t     unsigned long *percent)\n{\n\tunsigned long long coremem;\n\tchar *endptr;\n\n\tif (!p)\n\t\treturn -EINVAL;\n\n\t/* Value may be a percentage of total memory, otherwise bytes */\n\tcoremem = simple_strtoull(p, &endptr, 0);\n\tif (*endptr == '%') {\n\t\t/* Paranoid check for percent values greater than 100 */\n\t\tWARN_ON(coremem > 100);\n\n\t\t*percent = coremem;\n\t} else {\n\t\tcoremem = memparse(p, &p);\n\t\t/* Paranoid check that UL is enough for the coremem value */\n\t\tWARN_ON((coremem >> PAGE_SHIFT) > ULONG_MAX);\n\n\t\t*core = coremem >> PAGE_SHIFT;\n\t\t*percent = 0UL;\n\t}\n\treturn 0;\n}\n\nbool mirrored_kernelcore __initdata_memblock;\n\n/*\n * kernelcore=size sets the amount of memory for use for allocations that\n * cannot be reclaimed or migrated.\n */\nstatic int __init cmdline_parse_kernelcore(char *p)\n{\n\t/* parse kernelcore=mirror */\n\tif (parse_option_str(p, \"mirror\")) {\n\t\tmirrored_kernelcore = true;\n\t\treturn 0;\n\t}\n\n\treturn cmdline_parse_core(p, &required_kernelcore,\n\t\t\t\t  &required_kernelcore_percent);\n}\nearly_param(\"kernelcore\", cmdline_parse_kernelcore);\n\n/*\n * movablecore=size sets the amount of memory for use for allocations that\n * can be reclaimed or migrated.\n */\nstatic int __init cmdline_parse_movablecore(char *p)\n{\n\treturn cmdline_parse_core(p, &required_movablecore,\n\t\t\t\t  &required_movablecore_percent);\n}\nearly_param(\"movablecore\", cmdline_parse_movablecore);\n\n/*\n * early_calculate_totalpages()\n * Sum pages in active regions for movable zone.\n * Populate N_MEMORY for calculating usable_nodes.\n */\nstatic unsigned long __init early_calculate_totalpages(void)\n{\n\tunsigned long totalpages = 0;\n\tunsigned long start_pfn, end_pfn;\n\tint i, nid;\n\n\tfor_each_mem_pfn_range(i, MAX_NUMNODES, &start_pfn, &end_pfn, &nid) {\n\t\tunsigned long pages = end_pfn - start_pfn;\n\n\t\ttotalpages += pages;\n\t\tif (pages)\n\t\t\tnode_set_state(nid, N_MEMORY);\n\t}\n\treturn totalpages;\n}\n\n/*\n * This finds a zone that can be used for ZONE_MOVABLE pages. The\n * assumption is made that zones within a node are ordered in monotonic\n * increasing memory addresses so that the \"highest\" populated zone is used\n */\nstatic void __init find_usable_zone_for_movable(void)\n{\n\tint zone_index;\n\tfor (zone_index = MAX_NR_ZONES - 1; zone_index >= 0; zone_index--) {\n\t\tif (zone_index == ZONE_MOVABLE)\n\t\t\tcontinue;\n\n\t\tif (arch_zone_highest_possible_pfn[zone_index] >\n\t\t\t\tarch_zone_lowest_possible_pfn[zone_index])\n\t\t\tbreak;\n\t}\n\n\tVM_BUG_ON(zone_index == -1);\n\tmovable_zone = zone_index;\n}\n\n/*\n * Find the PFN the Movable zone begins in each node. Kernel memory\n * is spread evenly between nodes as long as the nodes have enough\n * memory. When they don't, some nodes will have more kernelcore than\n * others\n */\nstatic void __init find_zone_movable_pfns_for_nodes(void)\n{\n\tint i, nid;\n\tunsigned long usable_startpfn;\n\tunsigned long kernelcore_node, kernelcore_remaining;\n\t/* save the state before borrow the nodemask */\n\tnodemask_t saved_node_state = node_states[N_MEMORY];\n\tunsigned long totalpages = early_calculate_totalpages();\n\tint usable_nodes = nodes_weight(node_states[N_MEMORY]);\n\tstruct memblock_region *r;\n\n\t/* Need to find movable_zone earlier when movable_node is specified. */\n\tfind_usable_zone_for_movable();\n\n\t/*\n\t * If movable_node is specified, ignore kernelcore and movablecore\n\t * options.\n\t */\n\tif (movable_node_is_enabled()) {\n\t\tfor_each_mem_region(r) {\n\t\t\tif (!memblock_is_hotpluggable(r))\n\t\t\t\tcontinue;\n\n\t\t\tnid = memblock_get_region_node(r);\n\n\t\t\tusable_startpfn = memblock_region_memory_base_pfn(r);\n\t\t\tzone_movable_pfn[nid] = zone_movable_pfn[nid] ?\n\t\t\t\tmin(usable_startpfn, zone_movable_pfn[nid]) :\n\t\t\t\tusable_startpfn;\n\t\t}\n\n\t\tgoto out2;\n\t}\n\n\t/*\n\t * If kernelcore=mirror is specified, ignore movablecore option\n\t */\n\tif (mirrored_kernelcore) {\n\t\tbool mem_below_4gb_not_mirrored = false;\n\n\t\tif (!memblock_has_mirror()) {\n\t\t\tpr_warn(\"The system has no mirror memory, ignore kernelcore=mirror.\\n\");\n\t\t\tgoto out;\n\t\t}\n\n... [Diff truncated. Dropped 1938 lines] ...\n\n\n\t/* Accounting of total+free memory is stable at this point. */\n\tmem_init_print_info();\n\tbuffer_init();\n\n\t/* Discard memblock private memory */\n\tmemblock_discard();\n\n\tfor_each_node_state(nid, N_MEMORY)\n\t\tshuffle_free_memory(NODE_DATA(nid));\n\n\tfor_each_populated_zone(zone)\n\t\tset_zone_contiguous(zone);\n\n\t/* Initialize page ext after all struct pages are initialized. */\n\tif (deferred_struct_pages)\n\t\tpage_ext_init();\n\n\tpage_alloc_sysctl_init();\n}\n\n/*\n * Adaptive scale is meant to reduce sizes of hash tables on large memory\n * machines. As memory size is increased the scale is also increased but at\n * slower pace.  Starting from ADAPT_SCALE_BASE (64G), every time memory\n * quadruples the scale is increased by one, which means the size of hash table\n * only doubles, instead of quadrupling as well.\n * Because 32-bit systems cannot have large physical memory, where this scaling\n * makes sense, it is disabled on such platforms.\n */\n#if __BITS_PER_LONG > 32\n#define ADAPT_SCALE_BASE\t(64ul << 30)\n#define ADAPT_SCALE_SHIFT\t2\n#define ADAPT_SCALE_NPAGES\t(ADAPT_SCALE_BASE >> PAGE_SHIFT)\n#endif\n\n/*\n * allocate a large system hash table from bootmem\n * - it is assumed that the hash table must contain an exact power-of-2\n *   quantity of entries\n * - limit is the number of hash buckets, not the total allocation size\n */\nvoid *__init alloc_large_system_hash(const char *tablename,\n\t\t\t\t     unsigned long bucketsize,\n\t\t\t\t     unsigned long numentries,\n\t\t\t\t     int scale,\n\t\t\t\t     int flags,\n\t\t\t\t     unsigned int *_hash_shift,\n\t\t\t\t     unsigned int *_hash_mask,\n\t\t\t\t     unsigned long low_limit,\n\t\t\t\t     unsigned long high_limit)\n{\n\tunsigned long long max = high_limit;\n\tunsigned long log2qty, size;\n\tvoid *table;\n\tgfp_t gfp_flags;\n\tbool virt;\n\tbool huge;\n\n\t/* allow the kernel cmdline to have a say */\n\tif (!numentries) {\n\t\t/* round applicable memory size up to nearest megabyte */\n\t\tnumentries = nr_kernel_pages;\n\n\t\t/* It isn't necessary when PAGE_SIZE >= 1MB */\n\t\tif (PAGE_SIZE < SZ_1M)\n\t\t\tnumentries = round_up(numentries, SZ_1M / PAGE_SIZE);\n\n#if __BITS_PER_LONG > 32\n\t\tif (!high_limit) {\n\t\t\tunsigned long adapt;\n\n\t\t\tfor (adapt = ADAPT_SCALE_NPAGES; adapt < numentries;\n\t\t\t     adapt <<= ADAPT_SCALE_SHIFT)\n\t\t\t\tscale++;\n\t\t}\n#endif\n\n\t\t/* limit to 1 bucket per 2^scale bytes of low memory */\n\t\tif (scale > PAGE_SHIFT)\n\t\t\tnumentries >>= (scale - PAGE_SHIFT);\n\t\telse\n\t\t\tnumentries <<= (PAGE_SHIFT - scale);\n\n\t\tif (unlikely((numentries * bucketsize) < PAGE_SIZE))\n\t\t\tnumentries = PAGE_SIZE / bucketsize;\n\t}\n\tnumentries = roundup_pow_of_two(numentries);\n\n\t/* limit allocation size to 1/16 total memory by default */\n\tif (max == 0) {\n\t\tmax = ((unsigned long long)nr_all_pages << PAGE_SHIFT) >> 4;\n\t\tdo_div(max, bucketsize);\n\t}\n\tmax = min(max, 0x80000000ULL);\n\n\tif (numentries < low_limit)\n\t\tnumentries = low_limit;\n\tif (numentries > max)\n\t\tnumentries = max;\n\n\tlog2qty = ilog2(numentries);\n\n\tgfp_flags = (flags & HASH_ZERO) ? GFP_ATOMIC | __GFP_ZERO : GFP_ATOMIC;\n\tdo {\n\t\tvirt = false;\n\t\tsize = bucketsize << log2qty;\n\t\tif (flags & HASH_EARLY) {\n\t\t\tif (flags & HASH_ZERO)\n\t\t\t\ttable = memblock_alloc(size, SMP_CACHE_BYTES);\n\t\t\telse\n\t\t\t\ttable = memblock_alloc_raw(size,\n\t\t\t\t\t\t\t   SMP_CACHE_BYTES);\n\t\t} else if (get_order(size) > MAX_PAGE_ORDER || hashdist) {\n\t\t\ttable = vmalloc_huge(size, gfp_flags);\n\t\t\tvirt = true;\n\t\t\tif (table)\n\t\t\t\thuge = is_vm_area_hugepages(table);\n\t\t} else {\n\t\t\t/*\n\t\t\t * If bucketsize is not a power-of-two, we may free\n\t\t\t * some pages at the end of hash table which\n\t\t\t * alloc_pages_exact() automatically does\n\t\t\t */\n\t\t\ttable = alloc_pages_exact(size, gfp_flags);\n\t\t\tkmemleak_alloc(table, size, 1, gfp_flags);\n\t\t}\n\t} while (!table && size > PAGE_SIZE && --log2qty);\n\n\tif (!table)\n\t\tpanic(\"Failed to allocate %s hash table\\n\", tablename);\n\n\tpr_info(\"%s hash table entries: %ld (order: %d, %lu bytes, %s)\\n\",\n\t\ttablename, 1UL << log2qty, get_order(size), size,\n\t\tvirt ? (huge ? \"vmalloc hugepage\" : \"vmalloc\") : \"linear\");\n\n\tif (_hash_shift)\n\t\t*_hash_shift = log2qty;\n\tif (_hash_mask)\n\t\t*_hash_mask = (1 << log2qty) - 1;\n\n\treturn table;\n}\n\nvoid __init memblock_free_pages(unsigned long pfn, unsigned int or